    class Solution
    {
        static long MaxSubArraySum(long[] arr)
        {
            long currentCount = 0;
            long maxCount = Int64.MinValue;
            for (int i = 0; i < arr.Length; i++)
            {
                currentCount += arr[i];
                if (currentCount > maxCount)
                {
                    maxCount = currentCount;
                }
                if (currentCount < 0)
                {
                    currentCount = 0;
                }
            }

            return maxCount;
        }

