func Max(x, y int64) int64 {
	if x > y {
		return x
	}
	return y
}

func Kadane(arr []int64) int64 {
	var maxSoFar, maxEnding int64 = 0, 0
	for _, x := range arr {
		maxEnding = Max(0, maxEnding + x)
		maxSoFar = Max(maxSoFar, maxEnding)
	}
